import {
  useId,
  type ComponentType,
  type CSSProperties,
  type ReactNode,
  type SVGProps,
} from "react";

type LogoProps = SVGProps<SVGSVGElement> & { className?: string };

type BrandAccent = {
  from: string;
  to: string;
};

function createRemoteLogo(
  src: string,
  options?: {
    style?: CSSProperties;
  },
) {
  return function RemoteLogo({ className }: LogoProps) {
    return (
      <img
        src={src}
        alt=""
        aria-hidden="true"
        className={className}
        decoding="async"
        loading="lazy"
        referrerPolicy="no-referrer"
        style={options?.style}
      />
    );
  };
}

/* — Browser -------------------------------------------------------- */

function BrowserLogo(props: LogoProps) {
  const uid = useId();
  const g1 = `${uid}-browser-g1`;
  const g2 = `${uid}-browser-g2`;
  return (
    <svg viewBox="0 0 32 32" fill="none" {...props}>
      <defs>
        <linearGradient id={g1} x1="6" y1="8" x2="26" y2="24" gradientUnits="userSpaceOnUse">
          <stop stopColor="#7C9CFF" />
          <stop offset="1" stopColor="#3656D4" />
        </linearGradient>
        <linearGradient id={g2} x1="10" y1="13" x2="22" y2="23" gradientUnits="userSpaceOnUse">
          <stop stopColor="#E6EEFF" />
          <stop offset="1" stopColor="#B8CBFF" />
        </linearGradient>
      </defs>
      <rect x="4.5" y="6" width="23" height="20" rx="5" fill={`url(#${g1})`} />
      <path d="M4.5 11.2h23" stroke="#DCE6FF" strokeWidth="1.2" opacity="0.85" />
      <circle cx="8.6" cy="8.8" r="0.9" fill="#F8FBFF" opacity="0.95" />
      <circle cx="11.4" cy="8.8" r="0.9" fill="#F8FBFF" opacity="0.82" />
      <circle cx="14.2" cy="8.8" r="0.9" fill="#F8FBFF" opacity="0.68" />
      <path
        d="M11 19.6c0-2.8 2.2-5 5-5 1.8 0 3.3.8 4.2 2.2l-1.7 1.2a3.1 3.1 0 0 0-2.5-1.3 3 3 0 0 0 0 6c1.2 0 2.1-.4 2.6-1.1v-.8h-2.5v-1.9h4.8v3.4a6.2 6.2 0 0 1-4.9 2.3c-2.8 0-5-2.2-5-5Z"
        fill={`url(#${g2})`}
      />
    </svg>
  );
}

