function GranolaLogo(props: LogoProps) {
  return (
    <svg viewBox="0 0 550 550" fill="none" shapeRendering="geometricPrecision" {...props}>
      <rect width="550" height="550" rx="60" fill="#B2C248" />
      <path d={GRANOLA_PATH} fill="#1E1E1E" />
    </svg>
  );
}

